mapper.select:
select *
from question

     and id = #{id}
     and subject = #{subject}
     and type = #{type}
     and difficulty = #{difficulty}
     and status = #{status}
     and title like concat('%', #{title}, '%')

order by id desc

mapper.update:
update question
subject = #{subject}, type = #{type}, title = #{title}, option_a = #{optionA}, option_b = #{optionB}, option_c = #{optionC}, option_d = #{optionD}, correct_answer = #{correctAnswer}, analysis = #{analysis}, difficulty = #{difficulty}, status = #{status}, update_time = #{updateTime}
where id = #{id}
